#include <iostream>

void step3(int x)
{
    std::cout << "step3 received: " << x << '\n';
}

void step2(int x)
{
    std::cout << "step2 received: " << x << '\n';
    step3(x + 1);
}

void step1(int x)
{
    std::cout << "step1 received: " << x << '\n';
    step2(x + 1);
}

int main()
{
    int n = 0;
    std::cin >> n;
    step1(n);
    return 0;
}

